sub extract_text {
    my ($pdf_file, $pattern) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $text = '';
    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->open_page($page);
        my $text_obj = $page_obj->text;
        $text .= $text_obj->textout($text_obj->text($page_obj));
    }

